import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetShotsByProjectSequenceNode(BaseNode):
    name = "Prism: Get Shots by Project+Sequence"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("project", "dict")
        self.add_input("sequence", "string", widget_type="text", default="")
        self.add_output("shots", "list")
        self.add_output("count", "int")

    def _project_path(self, project):
        path = project.get('project_path', '')
        if not path:
            cfg = project.get('configPath', '')
            if cfg:
                path = os.path.dirname(os.path.dirname(cfg))
        return path

    def _get_sequences_and_shots(self, core):
        result = core.entities.getShots()
        try:
            sequences, shots = result
            return list(sequences or []), list(shots or [])
        except (TypeError, ValueError):
            shots = list(result or [])
            sequences = list(dict.fromkeys(str(s.get('sequence', '')) for s in shots if s.get('sequence')))
            return sequences, shots

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        project = inputs.get('project') or {}
        sequence = (inputs.get('sequence') or '').strip()
        if core is None:
            self.log_error('No PrismCore found.')
            return {'shots': [], 'count': 0}
        if not project:
            self.log_error('No project provided.')
            return {'shots': [], 'count': 0}
        prj_path = self._project_path(project)
        if not prj_path:
            self.log_error('Cannot determine project path from project dict.')
            return {'shots': [], 'count': 0}
        try:
            core.changeProject(prj_path)
        except Exception as e:
            self.log_error(f'changeProject failed: {e}')
            return {'shots': [], 'count': 0}
        try:
            _, shots = self._get_sequences_and_shots(core)
            if sequence:
                seq_lower = sequence.lower()
                shots = [s for s in shots if str(s.get('sequence', '')).lower() == seq_lower]
            label = sequence or '*'
            self.log_info(f"Found {len(shots)} shot(s) in '{project.get('name', '')}' / '{label}'")
            return {'shots': shots, 'count': len(shots)}
        except Exception as e:
            self.log_error(f'getShots failed: {e}')
            return {'shots': [], 'count': 0}

def register_node():
    return PrismGetShotsByProjectSequenceNode
